            </div>

            <div className="text-center py-8 text-sm text-gray-400">
              <p>
                Connect Sanity CMS to see your published posts here.
              </p>
              <p className="mt-1">
                Or{" "}
                <Link href="/demo" className="text-indigo-600 hover:underline">
                  view the demo
                </Link>{" "}
                to see the paywall in action.
              </p>
            </div>
          </>
