import { Author } from "@/../../types";

interface AuthorBadgeProps {
  author: Author;
  publishedAt: string;
}

export default function AuthorBadge({ author, publishedAt }: AuthorBadgeProps) {
  const date = new Date(publishedAt).toLocaleDateString("en-US", {
    year: "numeric",
    month: "long",
    day: "numeric",
  });

  return (
