              ? "max-h-[600px] overflow-hidden"
              : ""
          }
        >
          <div className="font-[family-name:var(--font-body)] text-gray-800 leading-relaxed space-y-5 text-[17px]">
            {paragraphs.map((p, i) => (
              <p key={i}>{p}</p>
            ))}
          </div>
        </div>

        {post.isPremium && (
          <PaywallOverlay
            stripeCheckout={stripeCheckout}
            authButton={authButton}
          />
        )}
      </div>
    </article>
  );
}

