     6→  useStripe,
     7→  useElements,
     8→} from "@stripe/react-stripe-js";
     9→import { useState } from "react";
    10→
    11→export default function StripeCheckout() {
    12→  const stripe = useStripe();
    13→  const elements = useElements();
    14→  const [loading, setLoading] = useState(false);
    15→  const [message, setMessage] = useState<string | null>(null);
    16→
    17→  const handleSubmit = async (e: React.FormEvent) => {
    18→    e.preventDefault();
    19→    if (!stripe || !elements) return;
    20→
    21→    setLoading(true);
    22→    const { error } = await stripe.confirmPayment({
    23→      elements,
    24→      confirmParams: {
    25→        return_url: `${window.location.origin}/demo?success=true`,
    26→      },
    27→    });
    28→
    29→    if (error) {
    30→      setMessage(error.message || "Payment failed");
    31→    }
    32→    setLoading(false);
    33→  };
    34→
    35→  return (
    36→    <form onSubmit={handleSubmit} className="space-y-3">
    37→      <ExpressCheckoutElement
    38→        onConfirm={async () => {
    39→          if (!stripe || !elements) return;
    40→          await stripe.confirmPayment({
    41→            elements,
    42→            confirmParams: {
    43→              return_url: `${window.location.origin}/demo?success=true`,
    44→            },
    45→          });
    46→        }}
    47→      />
    48→      <div className="flex items-center gap-3 my-3">
    49→        <div className="flex-1 h-px bg-gray-200" />
    50→        <span className="text-xs text-gray-400 uppercase tracking-wide">
    51→          Or pay with card
    52→        </span>
    53→        <div className="flex-1 h-px bg-gray-200" />
    54→      </div>
    55→      <PaymentElement />
    56→      <button
    57→        type="submit"
    58→        disabled={!stripe || loading}
    59→        className="w-full bg-indigo-600 text-white rounded-md py-2.5 text-sm font-semibold hover:bg-indigo-700 transition-colors disabled:opacity-50 disabled:cursor-not-allowed"
    60→      >
    61→        {loading ? "Processing..." : "Subscribe — $9.99/mo"}
    62→      </button>
    63→      {message && (
    64→        <p className="text-sm text-red-500 text-center">{message}</p>
    65→      )}
    66→    </form>
    67→  );
    68→}
    69→

