     1→"use client";
     2→
     3→import { useState, useEffect, ReactNode } from "react";
     4→import { Elements } from "@stripe/react-stripe-js";
     5→import { getStripe } from "@/app/lib/stripe";
     6→import type { Stripe, StripeElementsOptions } from "@stripe/stripe-js";
     7→
     8→interface StripeProviderProps {
     9→  children: ReactNode;
    10→}
    11→
    12→export default function StripeProvider({ children }: StripeProviderProps) {
    13→  const [stripe, setStripe] = useState<Stripe | null>(null);
    14→  const [clientSecret, setClientSecret] = useState<string | null>(null);
    15→  const [error, setError] = useState<string | null>(null);
    16→
    17→  useEffect(() => {
    18→    const stripePromise = getStripe();
    19→    if (!stripePromise) return;
    20→
    21→    stripePromise.then(setStripe);
    22→
    23→    fetch("/api/stripe/create-payment-intent", { method: "POST" })
    24→      .then((res) => res.json())
    25→      .then((data) => {
    26→        if (data.clientSecret) {
    27→          setClientSecret(data.clientSecret);
    28→        } else {
    29→          setError(data.error || "Failed to create payment intent");
    30→        }
    31→      })
    32→      .catch(() => setError("Failed to connect to payment server"));
    33→  }, []);
    34→
    35→  if (error || !stripe || !clientSecret) {
    36→    return <>{children}</>;
    37→  }
    38→
    39→  const options: StripeElementsOptions = {
    40→    clientSecret,
    41→    appearance: {
    42→      theme: "stripe",
    43→      variables: {
    44→        colorPrimary: "#4f46e5",
    45→        borderRadius: "8px",
    46→      },
    47→    },
    48→  };
    49→
    50→  return (
    51→    <Elements stripe={stripe} options={options}>
    52→      {children}
    53→    </Elements>
    54→  );
    55→}
